/* ────────── Re-sort the combined array by canonical civilization order
   so that entries from stories.js (sorted) and stories-extended.js
   (newly added) interleave properly. The sort step at the end of
   stories.js already runs before this file loads, so we re-run it
   here too. ────────── */
(function () {
    if (!window.MYTHOLOGY || !window.MYTHOLOGY.civilizations) return;
    const order = window.MYTHOLOGY.civilizations.map(c => c.id);
    const indexOf = id => {
        const i = order.indexOf(id);
        return i < 0 ? 999 : i;
    };
    window.MYTHOLOGY.stories.sort((a, b) => {
        const da = indexOf(a.civilization);
        const db = indexOf(b.civilization);
        if (da !== db) return da - db;
        return 0;
    });
})();
